from math import isqrt
from sympy import prevprime, integer_log
def A333536(n):
    if n < 5: return int(not n==1)
    def g(x, m): return x.bit_length() if m==2 else sum(g(x//(m**i), prevprime(m))for i in range(integer_log(x, m)[0]+1))
